digraph simple_linear {
  graph [goal="Inspect the repository, make one targeted improvement, and summarize the result.", label="Simple Linear Workflow", spark.description="A minimal starter flow that plans a small change, executes it, and summarizes the outcome.", spark.title="Simple Linear Workflow", ui_default_llm_model="gpt-5.5", ui_default_llm_provider="codex"];
  done [allow_partial=false, auto_status=false, error_policy="continue", goal_gate=false, join_policy="wait_all", label="Done", max_parallel=4, reasoning_effort="high", shape="Msquare"];
  implement [allow_partial=false, auto_status=false, error_policy="continue", goal_gate=false, join_policy="wait_all", label="Implement", llm_model="gpt-5.5", max_parallel=4, prompt="Carry out the planned improvement in the repository and validate the result before moving on.", reasoning_effort="high", shape="box"];
  plan [allow_partial=false, auto_status=false, error_policy="continue", goal_gate=false, join_policy="wait_all", label="Plan", llm_model="gpt-5.5", max_parallel=4, prompt="Inspect the repository and plan the targeted improvement needed to satisfy the stated goal.", reasoning_effort="high", shape="box"];
  start [allow_partial=false, auto_status=false, error_policy="continue", goal_gate=false, join_policy="wait_all", label="Start", max_parallel=4, reasoning_effort="high", shape="Mdiamond"];
  summarize [allow_partial=false, auto_status=false, error_policy="continue", goal_gate=false, join_policy="wait_all", label="Summarize", llm_model="gpt-5.5", max_parallel=4, prompt="Summarize what changed, what was validated, and any remaining follow-up for the stated goal.", reasoning_effort="high", shape="box"];
  implement -> summarize [loop_restart=false];
  plan -> implement [loop_restart=false];
  start -> plan [loop_restart=false];
  summarize -> done [loop_restart=false];
}
